import streamlit as st
import pandas as pd
import numpy as np
st.set_page_config(page_title="IPL Analyzer", layout="wide")

ipl = pd.read_csv('ipl-matches.csv')
all_team =np.union1d(ipl['Team1'] , ipl['Team2'])
venue = ipl['Venue'].unique()
venue = pd.Series(venue).str.split(',').explode()
city = ipl['City'].unique()

st.title("Cricket Analysis")
st.sidebar.title('IPL 2008 - 2022')
st.sidebar.header('IPL')
st.sidebar.image('data:image/jpeg;base64,')
st.write("The Indian Premier League (IPL) is a premier professional T20 cricket league in India, founded by the BCCI in 2008. Featuring 10 city-based franchises, it is one of the world's most popular and lucrative sports leagues, running annually between March and May. The tournament uses a round-robin and knockout format, concluding with play")
sidebar_option = st.sidebar.selectbox('Select Team',all_team)
city = st.sidebar.selectbox('All City Where Organize Ipl',city)
stadium = st.sidebar.selectbox('Stadium',venue)
st.title('=> Team1 Vs Team2')
col1 ,col2 = st.columns(2)
with col1:
    t = st.selectbox('Select Team',all_team)
with col2:
    t2 = st.selectbox('Select Team 2',all_team)
btn = st.button('Show')
if btn:
    a = (ipl['Team1'] == t) & (ipl['Team2'] == t2)
    b = (ipl['Team1'] == t2) & (ipl['Team2'] == t)
    teams = ipl[a | b]['WinningTeam'].value_counts()
    total_play = (ipl[a | b]).shape[0]
    st.write('Total Match',total_play)
    st.bar_chart(teams)
    st.dataframe(teams)
    if t == t2:
        st.error('Error')
    st.balloons()
st.title('=> All details about any Teams')
h = st.selectbox('select Team All Details',['Select Teams'] + all_team.tolist())
data = []

btn2 = st.button('Show All Details')
if btn2:
    play = ipl[(ipl['Team1'] == h) | (ipl['Team2'] == h)].shape[0]
    win = ipl[(ipl['WinningTeam'] == h)].shape[0]
    win_percentage = (win / play) * 100
    home_play = (ipl['Team1'] == h).sum()
    home_win = ((ipl['Team1'] == h) & (ipl['WinningTeam'] == h)).sum()
    home_win_percentage = (home_win / home_play) * 100
    outside_win = win - home_win

    data.append([play, win, win_percentage, home_play, home_win, home_win_percentage, outside_win])
    new_df = pd.DataFrame(data, columns=[
        'Play',
        'Win',
        'Win Percentage',
        'Home Play',
        'Home Win',
        'Home Win Percentage',
        'Outside Win'
    ])
    st.dataframe(new_df)

final = ipl[ipl['MatchNumber'] == 'Final']

final_all_team = pd.concat([final['Team1'],final['Team2']])
st.title('=> IPL Title Won By Teams')
btn3 = st.button('Sho IPL Title Won')
if btn3:
    winningTeams = ipl[ipl['MatchNumber'] == 'Final']['WinningTeam'].value_counts()
    st.bar_chart(winningTeams)
    st.dataframe(winningTeams)
st.title('=> IPL Teams Appreance In final')
btn4 = st.button('Teams Appreance In final')
if btn4:
    play_final_match = final_all_team.value_counts()
    st.dataframe(play_final_match)


